import styles from './Auth.module.css';
import eye from '../../images/auth/eye-crossed.svg';
import { Component } from 'react';
import UserList from './UserList';
import { useState } from 'react';
import { Link } from 'react-router-dom';



export const Login = ({ currentUsers, modal, changeRegistered }) => {
  // state = {
  //   email: '',
  //   password: '',
  // };

  const [modalData, setModalData] = useState(null);

  


  const collectInfo = (event) => {
    event.preventDefault();

    const email = event.target.email.value;
    const password = event.target.password.value;

    const user = currentUsers.find(
      (u) => u.email === email && u.password === password
    );



    if (user) {
      setModalData({ text: "You succsesfully logged in!", buttonText: "continue" });
    } else {
      setModalData({
        text: "This accaunt not registered yet. Would you like to register it??",
        buttonText: "register",
      });
    }

    event.target.email.value = "";
    event.target.password.value = "";
  };

  const closeModal = () => setModalData(null);

  return (
    <>
      <form className={styles.loginForm} onSubmit={collectInfo}>
        <h2 className={styles.name}>Log in</h2>
        <ul className={styles.list}>
          <li className={styles.item}>
            <p className={styles.label}>Enter your email address</p>
            <input
              name="email"
              type="email"
              className={styles.input}
              placeholder="email@gmail.com"
              key="email-input-login"
            />
          </li>
          <li className={styles.item}>
            <p className={styles.label}>Enter a password</p>
            <input
              name="password"
              type="password"
              className={styles.input}
              placeholder="*****"
              key="password-input-login"
            />
            <img src={eye} alt="" className={styles.eye} />
          </li>
        </ul>
        
        <Link to='/profile' className={styles.btn} type="submit">
          Login
        </Link>
<p className={styles.sugtestion}>
  Don’t have an account?{" "}
  <a href="#" className={styles.link} onClick={(e) => { e.preventDefault(); changeRegistered(); }}>
    Register
  </a>
</p>

      </form>


      {modalData && (
        <div className={styles.modalOverlay} onClick={closeModal}>
          <div
            className={styles.modal}
            onClick={(e) => e.stopPropagation()} 
          >
            <p>{modalData.text}</p>
            <button className={styles.modalButton} onClick={closeModal}>
              {modalData.buttonText}
            </button>
          </div>
        </div>
      )}
    </>
  );
};



